import{_ as s,o as a,c as t,ah as i}from"./chunks/framework.C8Zd3T50.js";const k=JSON.parse('{"title":"Development Overview","description":"","frontmatter":{},"headers":[],"relativePath":"dev/index.md","filePath":"dev/index.md"}'),n={name:"dev/index.md"};function o(r,e,l,h,p,d){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="development-overview" tabindex="-1">Development Overview <a class="header-anchor" href="#development-overview" aria-label="Permalink to &quot;Development Overview&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Quick start — install the CLI</p><p>Most development workflows benefit from having the <code>384</code> CLI. If you have <a href="https://deno.com" target="_blank" rel="noreferrer">Deno</a> 2.x:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deno</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 384</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-read</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-write</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-net</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://c3.384.dev/api/v2/page/8yp0Lyfr/384.ts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.deno/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>See <a href="/BhoW6b/cli.html">CLI Reference</a> for details.</p></div><p>os384 is both a <strong>platform</strong> (channel server, storage server, loader) and a <strong>library</strong> (lib384) that runs in the browser. Depending on what you&#39;re working on, you&#39;ll find yourself in one of four scenarios. Pick the one that matches what you&#39;re doing.</p><hr><h2 id="_1-—-building-apps-with-os384" tabindex="-1">1 — Building apps with os384 <a class="header-anchor" href="#_1-—-building-apps-with-os384" aria-label="Permalink to &quot;1 — Building apps with os384&quot;">​</a></h2><p>You&#39;re writing browser applications that use os384&#39;s encrypted storage and channels. You&#39;re not modifying any os384 infrastructure — just using it the same way a web developer uses any cloud platform.</p><p><strong>What you need:</strong> a browser, your editor, and the os384 docs.</p><p>lib384 is loaded from a stable URL served by the os384 channel infrastructure. No install step, no build step — just import it in a <code>&lt;script type=&quot;module&quot;&gt;</code> tag or load the IIFE bundle. The <a href="./../loader.html">Loader</a> at 384.dev handles key management and app launch for end users.</p><p>Start with the <a href="./../getting-started.html">Getting Started</a> page, then consult the <a href="https://github.com/os384/lib384" target="_blank" rel="noreferrer">lib384 API reference</a> for what&#39;s available.</p><hr><h2 id="_2-—-working-on-lib384-or-the-servers" tabindex="-1">2 — Working on lib384 or the servers <a class="header-anchor" href="#_2-—-working-on-lib384-or-the-servers" aria-label="Permalink to &quot;2 — Working on lib384 or the servers&quot;">​</a></h2><p>You&#39;re modifying lib384 itself, or the channel/storage server code. You want a full local stack running so you can run regression tests without touching production and iterate fast.</p><p>This is the scenario where you run wrangler in two terminal windows, run <code>make test</code> in lib384, and work against localhost:3845 and localhost:3843.</p><p>→ <strong><a href="./local-stack.html">Local stack setup</a></strong> → <strong><a href="./regression-tests.html">Running regression tests</a></strong></p><hr><h2 id="_3-—-running-your-own-os384-instance" tabindex="-1">3 — Running your own os384 instance <a class="header-anchor" href="#_3-—-running-your-own-os384-instance" aria-label="Permalink to &quot;3 — Running your own os384 instance&quot;">​</a></h2><p>You want to host os384 privately — for yourself, a team, or your users — without modifying any server code. The entire stack ships as a Docker Compose file.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> os384/services/docker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>All five services start automatically on their respective ports (3840–3849). You don&#39;t need a Cloudflare account; wrangler runs in local mode inside each container.</p><p>See the <a href="https://github.com/os384/services" target="_blank" rel="noreferrer">services README</a> for the full setup.</p><hr><h2 id="_4-—-deploying-to-a-linux-vm" tabindex="-1">4 — Deploying to a Linux VM <a class="header-anchor" href="#_4-—-deploying-to-a-linux-vm" aria-label="Permalink to &quot;4 — Deploying to a Linux VM&quot;">​</a></h2><p>Same as running your own instance, but on a Hetzner/DigitalOcean/Linode VM. Add a reverse proxy (nginx or Caddy) in front to handle TLS and route ports.</p><p>The Docker stack is the same; the Compose file works identically on Linux. The only differences are paths for persistent storage (see <a href="./../local-storage.html">Local storage paths</a> for the Linux layout) and whatever DNS/TLS setup you prefer.</p><hr><h2 id="the-two-key-components" tabindex="-1">The two key components <a class="header-anchor" href="#the-two-key-components" aria-label="Permalink to &quot;The two key components&quot;">​</a></h2><p><strong>lib384</strong> is the TypeScript/Deno runtime library that runs in every browser app. Think of it the way you&#39;d think of libc for Unix, or the Deno standard library — it&#39;s the foundational layer everything builds on. Source: <code>lib384/</code>.</p><p><strong>Loader</strong> is the browser microkernel. It manages the user&#39;s wallet (key material), resolves channel page URIs, and launches apps in origin-isolated subdomains. It&#39;s the VMM in the analogy. Source: <code>loader/</code>.</p><p>The servers (channel, storage) are deliberately lean — the channel server is under 2500 lines of TypeScript, the storage server under 500. The complexity lives in lib384 and in the cryptographic protocol, not in the server.</p>`,29)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
